// SCRIPT EXECUTION
// ============================================================

async function run() {
  console.log('Fetching House Democrats and issues from database...')

  // Fetch all House members
  const { data: reps, error: repErr } = await supabase
    .from('politicians')
    .select('id, slug, name, party, chamber')
    .eq('chamber', 'house')
  if (repErr) { console.error('Error fetching representatives:', repErr.message); process.exit(1) }
  console.log(`Found ${reps.length} House members in DB`)

  // Fetch all issues
  const { data: issues, error: issErr } = await supabase
    .from('issues')
    .select('id, slug')
  if (issErr) { console.error('Error fetching issues:', issErr.message); process.exit(1) }
  console.log(`Found ${issues.length} issues in DB`)

  // Build lookup maps
  const issueMap = {}
  for (const i of issues) issueMap[i.slug] = i.id

  const repMap = {}
  for (const r of reps) repMap[r.slug] = r

  // Build upsert rows
  const rows = []
  let matched = 0
  let missing = 0
  const missingSlugs = []

  for (const [slug, stances] of Object.entries(STANCES)) {
    const rep = repMap[slug]
    if (!rep) {
      missing++
      missingSlugs.push(slug)
      continue
    }
    matched++

    for (const [issueSlug, data] of Object.entries(stances)) {
      const issueId = issueMap[issueSlug]
      if (!issueId) {
        console.warn(`  Warning: issue slug "${issueSlug}" not found in DB`)
        continue
      }
      rows.push({
        politician_id: rep.id,
        issue_id: issueId,
        stance: data.stance,
        summary: data.summary,
        source_url: null,
      })
    }
  }

  console.log(`\nMatched ${matched} House Democrats to DB records`)
  if (missing > 0) {
    console.warn(`Could not find ${missing} reps in DB: ${missingSlugs.join(', ')}`)
  }
  console.log(`Generated ${rows.length} stance records to upsert`)

  // Upsert in batches
  const BATCH = 500
  let upserted = 0
  let errors = 0

  for (let i = 0; i < rows.length; i += BATCH) {
    const batch = rows.slice(i, i + BATCH)
    const { error } = await supabase.from('politician_issues').upsert(batch, {
      onConflict: 'politician_id,issue_id',
    })
    if (error) {
      console.error(`Batch ${Math.floor(i / BATCH) + 1} error:`, error.message)
      errors++
    } else {
      upserted += batch.length
      console.log(`  Batch ${Math.floor(i / BATCH) + 1}: ${upserted}/${rows.length} upserted`)
    }
  }

  console.log(`\nDone! Upserted ${upserted} real stances (${errors} batch errors)`)

  // Verify
  const { count } = await supabase
    .from('politician_issues')
    .select('*', { count: 'exact', head: true })
  console.log(`Total stances in DB: ${count}`)
}

run().catch(console.error)
